section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/dependency-spike-kill-criteria-template.json",
  "title": "Dependency Spike Kill-Criteria Template",
  "type": "object",
  "required": [
    "artefact_id",
    "dependency_name",
    "criteria",
    "timebox",
    "verdict",
    "rationale",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "criteria": {
      "type": "array",
      "minItems": 3,
      "description": "list of criterion objects {axis, operator, threshold, measurement_source}"
    },
    "timebox": {
      "type": "string",
      "description": "ISO-8601 duration committed before spike start"
    },
    "verdict": {
      "type": "string",
      "description": "kill | continue | adopt"
    },
    "rationale": {
      "type": "string",
      "minLength": 1,
      "description": "one-line justification of verdict"
    },
    "dependency_name": {
      "type": "string",
      "description": "required field dependency_name",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
